def f8(s, a):
    if not (isinstance(a, (tuple, list)) and len(a) == 2): return False
    try: r = int(a[0]); c = int(a[1])
    except: return False
    h = len(s); w = len(s[0]) if h else 0
    if not (0 <= r < h and 0 <= c < w): return False
    count = 0
    for i in range(r+1, h):
        if s[i][c] == stf.RED:
            count += 1
        else:
            break
    return count >= 2

def f10(s, a):
    if not (isinstance(a, (tuple, list)) and len(a) == 2): return False
    try: r = int(a[0]); c = int(a[1])
    except: return False
    h = len(s); w = len(s[0]) if h else 0
    if not (0 <= r < h and 0 <= c < w): return False
    below = r+1
    while below < h and s[below][c] == stf.RED:
        below += 1
    if below < h:
        return s[below][c] == stf.EMPTY
    return False

def f11(s, a):
    if not (isinstance(a, (tuple, list)) and len(a) == 2): return False
    try: r = int(a[0]); c = int(a[1])
    except: return False
    h = len(s); w = len(s[0]) if h else 0
    if not (0 <= r < h and 0 <= c < w): return False
    # Empty cell, RED directly below, no empty between
    if s[r][c] != stf.EMPTY or r == h-1 or s[r+1][c] != stf.RED:
        return False
    for i in range(r+2, h):
        if s[i][c] == stf.EMPTY:
            return False
        if s[i][c] != stf.RED:
            break
    return True

