def f14(s, a):
    if not (isinstance(a, (tuple, list)) and len(a) == 2): return False
    try: r = int(a[0]); c = int(a[1])
    except: return False
    h = len(s); w = len(s[0]) if h else 0
    if not (0 <= r < h and 0 <= c < w): return False
    # Empty cell with RED stack below, gap inside stack
    i = r+1
    found_red = False
    gap = False
    while i < h:
        if s[i][c] == stf.RED:
            found_red = True
            if gap:
                return True
        elif s[i][c] == stf.EMPTY:
            gap = True
        else:
            break
        i += 1
    return False

